INSERT INTO `v1_4dfc3d25a25659e4b0270eb758bf265d270c02e0a43fa4fd82be25b07014004b` VALUES (1, 1, 1, "コラボレイドイベント「ゾンビランドコネクト！Re:DIEve」では、\n特別なストーリーをお楽しみいただけます。イベントボスの初回討伐時や\n完全討伐を達成した際にストーリーが解放されるようですよ。", 1011);
INSERT INTO `v1_4dfc3d25a25659e4b0270eb758bf265d270c02e0a43fa4fd82be25b07014004b` VALUES (1, 1, 2, "イベントボスには非常に高い「Total HP」が設定されております。\n「Total HP」は、皆さまがバトル中に与えたダメージの分だけ減らせる\nのだとか。豪華報酬を目指し、力を合わせて討伐いたしましょう。", 1012);
INSERT INTO `v1_4dfc3d25a25659e4b0270eb758bf265d270c02e0a43fa4fd82be25b07014004b` VALUES (1, 1, 3, "ボスバトルは、イベント期間中に配布される「討伐チケット」を消費して\n挑戦できます。また、難易度は「ボス詳細」から変更できますよ。\n討伐を達成した難易度はスキップも行えるので、活用してくださいまし。", 1013);
INSERT INTO `v1_4dfc3d25a25659e4b0270eb758bf265d270c02e0a43fa4fd82be25b07014004b` VALUES (2, 1, 4, "報酬交換では「討伐報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 1021);
